function solve(points: number[][]): number {
    const n = points.length;
    const slopeMap: Map<string, number[]> = new Map();

    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const [x1, y1] = points[i];
            const [x2, y2] = points[j];
            let slope: string;

            if (x1 === x2) {
                slope = "inf"; // vertical line
            } else {
                slope = (y2 - y1).toString() + "/" + (x2 - x1).toString();
            }

            if (!slopeMap.has(slope)) {
                slopeMap.set(slope, []);
            }
            slopeMap.get(slope)!.push(i);
        }
    }

    let count = 0;

    for (const [slope, indices] of slopeMap.entries()) {
        if (indices.length < 2) continue;

        for (let i = 0; i < indices.length; i++) {
            for (let j = i + 1; j < indices.length; j++) {
                const p1 = indices[i];
                const p2 = indices[j];

                const [x1, y1] = points[p1];
                const [x2, y2] = points[p2];

                // Check if there are at least two other points on the same line
                const linePoints = slopeMap.get(slope)!;
                const linePointsCount = linePoints.length;

                if (linePointsCount < 4) continue;

                // Count the number of pairs of points that form a line with the same slope
                const totalPairs = (linePointsCount - 2) * (linePointsCount - 3) / 2;
                count += totalPairs;
            }
        }
    }

    return count;
}

